CODE = 'NSAIRBCRMCOM' OR DIM_BASEL_METHODOLOGY.V_BASEL_METHOD_CODE IN ( 'NSAIRBCEM' ,'NSFIRBCEM' ,'NSSTDCEM' ) ) THEN COALESCE(FSI_CAP_DERIVATIVES.N_LGD_PERCENT_PRE_CRM, 0) END) N_NETTABLE_POOL_LGD ,MAX(FSI_CAP_DERIVATIVES.F_COUNTERPARTY_CMC_FLAG) F_COUNTERPARTY_CMC ,MAX(FSI_CAP_DERIVATIVES.N_HOLDING_PERIOD) N_HOLDING_PERIOD ,COUNT(CASE  WHEN FSI_CAP_DERIVATIVES.f_cleared_transaction_flag = 'N' THEN FSI_CAP_DERIVATIVES.f_cleared_transaction_flag END) N_NO_OF_TRADES_NETTING_SET ,COUNT(CASE  WHEN FSI_CAP_DERIVATIVES.f_cleared_transaction_flag = 'N' AND FSI_CAP_DERIVATIVES.F_ILLIQUID_DERIVATIVES = 'Y' THEN FSI_CAP_DERIVATIVES.f_cleared_transaction_flag END) N_NO_OF_ILLIQUID_DERIVATIVES ,MIN(FSI_CAP_DERIVATIVES.F_ILLIQUID_COLLATERAL) F_ILLIQUID_COLLATERAL ,MAX(FSI_CAP_DERIVATIVES.N_CRM_METHOD_SKEY) N_CRM_METHOD_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_CAP_NETTABLE_POOL_SKEY) N_CAP_NETTABLE_POOL_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_CAP_RECORD_TYPE_SKEY) N_CAP_RECORD_TYPE_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_CAP_APPROACH_TYPE_SKEY) N_CAP_APPROACH_TYPE_SKEY ,MAX(FSI_CAP_DERIVATIVES.V_APPROACH_TYPE) V_APPROACH_TYPE ,MAX(FSI_CAP_DERIVATIVES.V_RECORD_TYPE) V_RECORD_TYPE ,MAX(FSI_CAP_DERIVATIVES.N_EAD_APP_SKEY) N_EAD_APP_SKEY ,MAX(FSI_CAP_DERIVATIVES.V_ACCOUNT_POOL_ID) V_ACCOUNT_POOL_ID ,MAX(FSI_CAP_DERIVATIVES.N_BASEL_PROD_TYPE_SKEY) N_BASEL_PROD_TYPE_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_STD_COUNTERPARTY_TYPE_SKEY) N_STD_COUNTERPARTY_TYPE_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_D_CUST_INDUSTRY_SKEY) N_D_CUST_INDUSTRY_SKEY ,MAX(FSI_CAP_DERIVATIVES.N_COUNTERPARTY_TYPE_SKEY) N_COUNTERPARTY_TYPE_SKEY FROM FSI_CAP_DERIVATIVES LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON FSI_CAP_DERIVATIVES.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN DIM_GAAP ON FSI_CAP_DERIVATIVES.N_GAAP_SKEY = DIM_GAAP.N_GAAP_SKEY LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_RUN_IDENTIFIER ON DIM_RUN_IDENTIFIER.N_RUN_IDENTIFIER_SKEY = FSI_CAP_DERIVATIVES.N_RUN_IDENTIFIER_SKEY 