GINED_TXN_IND ,MAX(FSI_NETTING_AGREEMENT_DETAILS.N_NET_COLLATERAL_AMOUNT) N_NET_INDEPENDENT_COLL_AMT ,FSI_CAP_DERIVATIVES.N_RUN_SKEY ,FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY ,FSI_CAP_DERIVATIVES.N_NETTING_AGREEMENT_SKEY ,FSI_CAP_DERIVATIVES.N_GAAP_SKEY FROM FSI_CAP_DERIVATIVES INNER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_NETTING_AGREEMENT_DETAILS ON FSI_NETTING_AGREEMENT_DETAILS.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FSI_NETTING_AGREEMENT_DETAILS.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND FSI_NETTING_AGREEMENT_DETAILS.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FSI_NETTING_AGREEMENT_DETAILS.N_NETTING_AGREEMENT_SKEY = FSI_CAP_DERIVATIVES.N_NETTING_AGREEMENT_SKEY LEFT OUTER JOIN FSI_NET_AGREEMENT_COLLATERALS ON FSI_NET_AGREEMENT_COLLATERALS.n_run_skey = FSI_CAP_DERIVATIVES.n_run_skey AND FSI_NET_AGREEMENT_COLLATERALS.N_mis_date_skey = FSI_CAP_DERIVATIVES.n_Mis_Date_Skey AND FSI_NET_AGREEMENT_COLLATERALS.n_netting_agreement_skey = FSI_CAP_DERIVATIVES.n_netting_agreement_skey AND Fsi_Net_Agreement_Collaterals.n_Party_Skey = COALESCE(FSI_CAP_DERIVATIVES.n_Cust_Skey, FSI_CAP_DERIVATIVES.n_issue_skey) AND Fsi_Net_Agreement_Collaterals.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY AND FSI_NET_AGREEMENT_COLLATERALS.V_MARGIN_TYPE = 'IM' INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_CAP_APPROACH_TYPE_SKEY INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_CAP_RECORD_TYPE_SKEY AND FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE IN ( 'DRV_NON_SEC_EXP' ,'INV_NON_SEC_EXP' ) WHERE DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND FSI_CAP_DERIVATIVES.N_RUN_SKEY = '870' GROUP BY FSI_CAP_DERIVATIVES.N_RUN_SKEY ,FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY ,FSI_CAP_DERIVATIVES.N_NETTING_AGREEMENT_SKEY ,FSI_CAP_DERIVATIVES.N_GAAP_SKEY ) NETTING_AGREEMENT_DETAILS ON NETTING_AGREEMENT_DETAILS.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND NETTING_AGREEMENT_DETAILS.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND NETTING_AGREEMENT_DETAILS.N_NETTING_AGREEMENT_SKEY = FSI_CAP_DERIVATIVES.N_NETTING_AGREEMENT_SKEY AND NETTING_AGREEMENT_DETAILS.N_GAAP_SKEY = FSI_CAP_DERIVATIVES.N_GAAP_SKEY INNER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_CAP_APPROACH_TYPE_SKEY INNER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY = FSI_CAP_DERIVATIVES.N_CAP_RECORD_TYPE_SKEY LEFT OUTER JOIN FSI_CP_NETTING_AGREEMENT_DTLS ON FSI_CP_NETTING_AGREEMENT_DTLS.N_MIS_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND FSI_CP_NETTING_AGREEMENT_DTLS.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FSI_CP_NETTING_AGREEMENT_DTLS.N_NETTING_AGREEMENT_SKEY = FSI_CAP_DERIVATIVES.N_NETTING_AGREEMENT_SKEY AND FSI_CP_NETTING_AGREEMENT_DTLS.N_COUNTERPARTY_SKEY = FSI_CAP_DERIVATIVES.N_CUST_SKEY INNER JOIN FSI_RUN_PARAMETER ON FSI_RUN_PARAMETER.N_DATE_SKEY = FSI_CAP_DERIVATIVES.N_MIS_DATE_SKEY AND FSI_RUN_PARAMETER.N_RUN_SKEY = FSI_CAP_DERIVATIVES.N_RUN_SKEY AND FSI_RUN_PARAMETER.N_RUN_PARAMETER_SETUP_SKEY = FSI_CAP_DERIVATIVES.N_RUN_PARAMETER_SETUP_SKEY AND COALESCE(FSI_RUN_PARAMETER.V_OTC_EAD_CALC_OPTION, 'OPTCOMSYS') = 'OPTCOMBNK' WHERE ((1=1) AND ( FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_EXP' ) AND ( FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = 'NSSTD' ) AND (9=9) AND (3=3)) LOG ERRORS INTO FSI_CAP_NETTABLE_POOL$ ('1776769376998_3254540_20260331_1_JOB_16563524574190') REJECT LIMIT 0;

